raw_outputs.groq2:
{
  "preconditions": [
    "a must be a number",
    "b must be a number",
    "a and b must be of the same type"
  ],
  "postconditions": [
    "a is equal to the sum of its original value and b"
  ],
  "edge_cases": [
    "if a is a complex number, its real and imaginary parts must be numbers",
    "if a is a complex number, b must be of the same type as a",
    "if a is a complex number, the result will be a complex number"
  ]
}

