{
  "preconditions": [
    "a must be a number",
    "b must be a number"
  ],
  "postconditions": [
    "a is equal to the result of a + b"
  ],
  "edge_cases": [
    "if a is not a number, raises TypeError",
    "if b is not a number, raises TypeError",
    "if a is a complex number, b must also be a complex number"
  ]
}
